def build_hub(r):
    return {"id":r[0],"display_name":r[1],"aliases":r[2],"type":r[3],"modes":r[4],
            "lat":r[5],"lon":r[6],"country":r[7],"importance":r[8],"strategic_role":r[9]}
if __name__=="__main__":
    with open("backend/data/canonical_hubs.json","r") as f: existing=json.load(f)
    existing_ids={h["id"] for h in existing}
    new=[build_hub(r) for r in RAW3 if r[0] not in existing_ids]
    merged=existing+new
    with open("backend/data/canonical_hubs.json","w") as f: json.dump(merged,f,indent=2)
    print(f"Part 3: +{len(new)}. Total: {len(merged)}")
